#!/usr/bin/env bash
# user-research-to-insight-ai.sh — 用户研究 → 洞察（user research to insight，含 AI 合成） SOP walkthrough for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
WORKFLOW="用户研究 → 洞察（user research to insight，含 AI 合成）"

usage() {
  cat <<EOF
user-research-to-insight-ai.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./user-research-to-insight-ai.sh             # interactive
  ./user-research-to-insight-ai.sh --dry-run
  ./user-research-to-insight-ai.sh --json
  ./user-research-to-insight-ai.sh --explain
  ./user-research-to-insight-ai.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "用户研究 → 洞察（user research to insight，含 AI 合成）" 工作流。

一句话: 从「不知道用户为什么这么做 / 要不要做某功能」到「有证据支撑的、可指导设计决策的洞察（persona / journey map / 痛点优先级）」。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定研究问题 + 选方法**: 先写「我们想知道什么」「这个决定取决于什么」，再选定性（访谈/可用性观察）还是定量（问卷/分析）。跳过→做了一堆访谈却答不了真正的决策问题，研究变摆设。 (evidence: [T03-S022])"
  "**招募 + 筛选**: 用 screener 找到目标用户群（5-8 人/段足够定性覆盖）。跳过→招到非目标用户，洞察偏差，结论不可信。 (evidence: [T03-S003, T03-S005])"
  "**执行（访谈 / 观察 / 测试）**: 问行为不问意见（\"上次你怎么做的\"而非\"你喜欢吗\"），录音/录屏。跳过→拿到的是自陈偏好（stated）而非真实行为（revealed），违背行业第一性。 (evidence: [T03-S022])"
  "**合成（synthesis）**: 转录 → 高亮关键句 → 按主题打标（affinity / 主题分析）→ 提炼 pattern。跳过→一堆原始素材没变成可行动洞察，等于没研究。 (evidence: [T03-S014])"
  "**可视化 + 交付**: 产出 persona / journey map / 洞察报告，标优先级，讲给团队。跳过→洞察停在研究员脑里，不影响产品决策。 (evidence: [T03-S006])"
)
declare -a FAILURE_MODES=(
  "问意见而非行为: 访谈里问\"你喜不喜欢 X\"得到的是礼貌假象。改为问\"上一次遇到 Y 你做了什么\"。 (evidence: [T03-S022])"
  "研究做了不落地: 交完报告团队照旧拍脑袋。把每条洞察绑定到一个具体待决策问题再交付。 (evidence: [T03-S021])"
  "过度研究: 低风险决策做大样本研究，拖慢交付。先评估「这个决定错了代价多大」再决定研究深度。 (evidence: [T03-S022])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "user-research-to-insight-ai-walkthrough"
fi
